<!DOCTYPE html>
<html>
<head>
<title>User Input Form</title>
</head>
<body>

<form id="userInputForm">
  <label for="userInput">Enter your text:</label><br>
  <textarea id="userInput" name="userInput" rows="4" cols="50"></textarea><br><br>
  <input type="submit" value="Submit">
</form>

<div id="output"></div>

<script>
  document.getElementById('userInputForm').addEventListener('submit', function(event) {
    event.preventDefault();
    const userInput = document.getElementById('userInput').value;

    // In a real application, you would send this data to a server to save it.
    // For this example, we will just display it on the page.
    const outputDiv = document.getElementById('output');
    outputDiv.innerHTML = "<h2>Submitted Text:</h2><p>" + userInput + "</p>";

    // Clear the form after submission
    document.getElementById('userInput').value = '';
  });
</script>

</body>
</html>
